import { request, authRequest } from "./api";
import { Course, UserProgress } from "../types/api.types";

export const coursesService = {
  // ... существующие методы ...

  // Получить курсы пользователя
  async getUserCourses(token: string): Promise<string[]> {
    const response = await authRequest("/users/me", token);
    return response.user.selectedCourses || [];
  },

  // Получить прогресс пользователя по курсу
  async getUserCourseProgress(
    courseId: string,
    token: string,
  ): Promise<UserProgress> {
    return authRequest(`/users/me/progress?courseId=${courseId}`, token);
  },

  // Получить прогресс по конкретной тренировке
  async getWorkoutProgress(
    courseId: string,
    workoutId: string,
    token: string,
  ): Promise<{
    workoutId: string;
    workoutCompleted: boolean;
    progressData: number[];
  }> {
    return authRequest(
      `/users/me/progress?courseId=${courseId}&workoutId=${workoutId}`,
      token,
    );
  },

  // Добавить курс пользователю
  async addCourseToUser(
    courseId: string,
    token: string,
  ): Promise<{ message: string }> {
    return authRequest("/users/me/courses", token, {
      method: "POST",
      body: JSON.stringify({ courseId }),
    });
  },

  // Удалить курс у пользователя
  async removeCourseFromUser(
    courseId: string,
    token: string,
  ): Promise<{ message: string }> {
    return authRequest(`/users/me/courses/${courseId}`, token, {
      method: "DELETE",
    });
  },

  // Сбросить прогресс по курсу
  async resetCourseProgress(
    courseId: string,
    token: string,
  ): Promise<{ message: string }> {
    return authRequest(`/courses/${courseId}/reset`, token, {
      method: "PATCH",
    });
  },
};
